def faster_mode_hops(spec: dict) -> int:
    """Fewest hops from start to target via road-only or rail-only travel; -1 if neither reaches."""
    road_adj = {}
    for pair in spec["roads"]:
        if pair[0] not in road_adj:
            road_adj[pair[0]] = []
        road_adj[pair[0]].append(pair[1])
    rail_adj = {}
    for pair in spec["rails"]:
        if pair[0] not in rail_adj:
            rail_adj[pair[0]] = []
        rail_adj[pair[0]].append(pair[1])
    road_d = {spec["start"]: 0}
    queue = [spec["start"]]
    while queue:
        n = queue.pop(0)
        if n in road_adj:
            for t in road_adj[n]:
                if t not in road_d:
                    road_d[t] = road_d[n] + 1
                    queue.append(t)
    rail_d = {spec["start"]: 0}
    queue = [spec["start"]]
    while queue:
        n = queue.pop(0)
        if n in rail_adj:
            for t in rail_adj[n]:
                if t not in rail_d:
                    rail_d[t] = rail_d[n] + 1
                    queue.append(t)
    dr = road_d.get(spec["target"], -1)
    dl = rail_d.get(spec["target"], -1)
    if dr == -1:
        return dl
    if dl == -1:
        return dr
    if dr < dl:
        return dr
    return dl
